import pickle
import io


class RestrictedUnpickler(pickle.Unpickler):
    """A restricted unpickler that only allows safe built-in types."""

    SAFE_TYPES = {
        'builtins': ('int', 'float', 'bool', 'str', 'bytes', 'list', 'tuple', 'dict')
    }

    def find_class(self, module, name):
        # Only allow specific modules and classes
        if module in self.SAFE_TYPES and name in self.SAFE_TYPES[module]:
            if name == 'int':
                return int
            elif name == 'float':
                return float
            elif name == 'bool':
                return bool
            elif name == 'str':
                return str
            elif name == 'bytes':
                return bytes
            elif name == 'list':
                return list
            elif name == 'tuple':
                return tuple
            elif name == 'dict':
                return dict
        raise pickle.UnpicklingError(
            f"Global '{module}.{name}' is forbidden"
        )


def getPickleData(pickled):
    '''
    Return deserialized data
    '''
    if isinstance(pickled, str):
        pickled = pickled.encode('utf-8')
    return RestrictedUnpickler(io.BytesIO(pickled)).load()
